@classmethod
def validate(cls):
    """验证必要配置"""
    errors = []
    if not cls.LLM_API_KEY:
        errors.append("LLM_API_KEY 未配置")
    if not cls.ZEP_API_KEY:
        errors.append("ZEP_API_KEY 未配置")
    return errors

