@classmethod
def get_run_state(cls, simulation_id: str) -> Optional[SimulationRunState]:
    """获取运行状态"""
    if simulation_id in cls._run_states:
        return cls._run_states[simulation_id]

    # 尝试从文件加载
    state = cls._load_run_state(simulation_id)
    if state:
        cls._run_states[simulation_id] = state
    return state

@classmethod


@classmethod
def _monitor_simulation(cls, simulation_id: str):
    """监控模拟进程，解析动作日志"""
    sim_dir = os.path.join(cls.RUN_STATE_DIR, simulation_id)

    # 新的日志结构：分平台的动作日志
    twitter_actions_log = os.path.join(sim_dir, "twitter", "actions.jsonl")
    reddit_actions_log = os.path.join(sim_dir, "reddit", "actions.jsonl")

    process = cls._processes.get(simulation_id)
    state = cls.get_run_state(simulation_id)

    if not process or not state:
        return

    twitter_position = 0
    reddit_position = 0

    try:
        while process.poll() is None:  # 进程仍在运行
            # 读取 Twitter 动作日志
            if os.path.exists(twitter_actions_log):
                twitter_position = cls._read_action_log(
                    twitter_actions_log, twitter_position, state, "twitter"
                )

            # 读取 Reddit 动作日志
            if os.path.exists(reddit_actions_log):
                reddit_position = cls._read_action_log(
                    reddit_actions_log, reddit_position, state, "reddit"
                )

            # 更新状态
            cls._save_run_state(state)
            time.sleep(2)

        # 进程结束后，最后读取一次日志
        if os.path.exists(twitter_actions_log):
            cls._read_action_log(twitter_actions_log, twitter_position, state, "twitter")
        if os.path.exists(reddit_actions_log):
            cls._read_action_log(reddit_actions_log, reddit_position, state, "reddit")

        # 进程结束
        exit_code = process.returncode

        if exit_code == 0:
            state.runner_status = RunnerStatus.COMPLETED
            state.completed_at = datetime.now().isoformat()
            logger.info(f"模拟完成: {simulation_id}")
        else:
            state.runner_status = RunnerStatus.FAILED
            # 从主日志文件读取错误信息
            main_log_path = os.path.join(sim_dir, "simulation.log")
            error_info = ""
            try:
                if os.path.exists(main_log_path):
                    with open(main_log_path, 'r', encoding='utf-8') as f:
                        error_info = f.read()[-2000:]  # 取最后2000字符
            except Exception:
                pass
            state.error = f"进程退出码: {exit_code}, 错误: {error_info}"
            logger.error(f"模拟失败: {simulation_id}, error={state.error}")

        state.twitter_running = False
        state.reddit_running = False
        cls._save_run_state(state)

    except Exception as e:
        logger.error(f"监控线程异常: {simulation_id}, error={str(e)}")
        state.runner_status = RunnerStatus.FAILED
        state.error = str(e)
        cls._save_run_state(state)

    finally:
        # 停止图谱记忆更新器
        if cls._graph_memory_enabled.get(simulation_id, False):
            try:
                ZepGraphMemoryManager.stop_updater(simulation_id)
                logger.info(f"已停止图谱记忆更新: simulation_id={simulation_id}")
            except Exception as e:
                logger.error(f"停止图谱记忆更新器失败: {e}")
            cls._graph_memory_enabled.pop(simulation_id, None)

        # 清理进程资源
        cls._processes.pop(simulation_id, None)
        cls._action_queues.pop(simulation_id, None)

        # 关闭日志文件句柄
        if simulation_id in cls._stdout_files:
            try:
                cls._stdout_files[simulation_id].close()
            except Exception:
                pass
            cls._stdout_files.pop(simulation_id, None)
        if simulation_id in cls._stderr_files and cls._stderr_files[simulation_id]:
            try:
                cls._stderr_files[simulation_id].close()
            except Exception:
                pass
            cls._stderr_files.pop(simulation_id, None)

@classmethod


@classmethod
def stop_simulation(cls, simulation_id: str) -> SimulationRunState:
    """停止模拟"""
    state = cls.get_run_state(simulation_id)
    if not state:
        raise ValueError(f"模拟不存在: {simulation_id}")

    if state.runner_status not in [RunnerStatus.RUNNING, RunnerStatus.PAUSED]:
        raise ValueError(f"模拟未在运行: {simulation_id}, status={state.runner_status}")

    state.runner_status = RunnerStatus.STOPPING
    cls._save_run_state(state)

    # 终止进程
    process = cls._processes.get(simulation_id)
    if process and process.poll() is None:
        try:
            cls._terminate_process(process, simulation_id)
        except ProcessLookupError:
            # 进程已经不存在
            pass
        except Exception as e:
            logger.error(f"终止进程组失败: {simulation_id}, error={e}")
            # 回退到直接终止进程
            try:
                process.terminate()
                process.wait(timeout=5)
            except Exception:
                process.kill()

    state.runner_status = RunnerStatus.STOPPED
    state.twitter_running = False
    state.reddit_running = False
    state.completed_at = datetime.now().isoformat()
    cls._save_run_state(state)

    # 停止图谱记忆更新器
    if cls._graph_memory_enabled.get(simulation_id, False):
        try:
            ZepGraphMemoryManager.stop_updater(simulation_id)
            logger.info(f"已停止图谱记忆更新: simulation_id={simulation_id}")
        except Exception as e:
            logger.error(f"停止图谱记忆更新器失败: {e}")
        cls._graph_memory_enabled.pop(simulation_id, None)

    logger.info(f"模拟已停止: {simulation_id}")
    return state

@classmethod


@classmethod
def cleanup_all_simulations(cls):
    """
    清理所有运行中的模拟进程

    在服务器关闭时调用，确保所有子进程被终止
    """
    # 防止重复清理
    if cls._cleanup_done:
        return
    cls._cleanup_done = True

    # 检查是否有内容需要清理（避免空进程的进程打印无用日志）
    has_processes = bool(cls._processes)
    has_updaters = bool(cls._graph_memory_enabled)

    if not has_processes and not has_updaters:
        return  # 没有需要清理的内容，静默返回

    logger.info("正在清理所有模拟进程...")

    # 首先停止所有图谱记忆更新器（stop_all 内部会打印日志）
    try:
        ZepGraphMemoryManager.stop_all()
    except Exception as e:
        logger.error(f"停止图谱记忆更新器失败: {e}")
    cls._graph_memory_enabled.clear()

    # 复制字典以避免在迭代时修改
    processes = list(cls._processes.items())

    for simulation_id, process in processes:
        try:
            if process.poll() is None:  # 进程仍在运行
                logger.info(f"终止模拟进程: {simulation_id}, pid={process.pid}")

                try:
                    # 使用跨平台的进程终止方法
                    cls._terminate_process(process, simulation_id, timeout=5)
                except (ProcessLookupError, OSError):
                    # 进程可能已经不存在，尝试直接终止
                    try:
                        process.terminate()
                        process.wait(timeout=3)
                    except Exception:
                        process.kill()

                # 更新 run_state.json
                state = cls.get_run_state(simulation_id)
                if state:
                    state.runner_status = RunnerStatus.STOPPED
                    state.twitter_running = False
                    state.reddit_running = False
                    state.completed_at = datetime.now().isoformat()
                    state.error = "服务器关闭，模拟被终止"
                    cls._save_run_state(state)

                # 同时更新 state.json，将状态设为 stopped
                try:
                    sim_dir = os.path.join(cls.RUN_STATE_DIR, simulation_id)
                    state_file = os.path.join(sim_dir, "state.json")
                    logger.info(f"尝试更新 state.json: {state_file}")
                    if os.path.exists(state_file):
                        with open(state_file, 'r', encoding='utf-8') as f:
                            state_data = json.load(f)
                        state_data['status'] = 'stopped'
                        state_data['updated_at'] = datetime.now().isoformat()
                        with open(state_file, 'w', encoding='utf-8') as f:
                            json.dump(state_data, f, indent=2, ensure_ascii=False)
                        logger.info(f"已更新 state.json 状态为 stopped: {simulation_id}")
                    else:
                        logger.warning(f"state.json 不存在: {state_file}")
                except Exception as state_err:
                    logger.warning(f"更新 state.json 失败: {simulation_id}, error={state_err}")

        except Exception as e:
            logger.error(f"清理进程失败: {simulation_id}, error={e}")

    # 清理文件句柄
    for simulation_id, file_handle in list(cls._stdout_files.items()):
        try:
            if file_handle:
                file_handle.close()
        except Exception:
            pass
    cls._stdout_files.clear()

    for simulation_id, file_handle in list(cls._stderr_files.items()):
        try:
            if file_handle:
                file_handle.close()
        except Exception:
            pass
    cls._stderr_files.clear()

    # 清理内存中的状态
    cls._processes.clear()
    cls._action_queues.clear()

    logger.info("模拟进程清理完成")

@classmethod

    original_sighup = signal.getsignal(signal.SIGHUP)

def cleanup_handler(signum=None, frame=None):
    """信号处理器：先清理模拟进程，再调用原处理器"""
    # 只有在有进程需要清理时才打印日志
    if cls._processes or cls._graph_memory_enabled:
        logger.info(f"收到信号 {signum}，开始清理...")
    cls.cleanup_all_simulations()

    # 调用原有的信号处理器，让 Flask 正常退出
    if signum == signal.SIGINT and callable(original_sigint):
        original_sigint(signum, frame)
    elif signum == signal.SIGTERM and callable(original_sigterm):
        original_sigterm(signum, frame)
    elif has_sighup and signum == signal.SIGHUP:
        # SIGHUP: 终端关闭时发送
        if callable(original_sighup):
            original_sighup(signum, frame)
        else:
            # 默认行为：正常退出
            sys.exit(0)
    else:
        # 如果原处理器不可调用（如 SIG_DFL），则使用默认行为
        raise KeyboardInterrupt

# 注册 atexit 处理器（作为备用）


@classmethod
def get_running_simulations(cls) -> List[str]:
    """
    获取所有正在运行的模拟ID列表
    """
    running = []
    for sim_id, process in cls._processes.items():
        if process.poll() is None:
            running.append(sim_id)
    return running

