_lock = threading.Lock()

def __new__(cls):
    """单例模式"""
    if cls._instance is None:
        with cls._lock:
            if cls._instance is None:
                cls._instance = super().__new__(cls)
                cls._instance._tasks: Dict[str, Task] = {}
                cls._instance._task_lock = threading.Lock()
    return cls._instance

